import java.io.*;

public class XSSSecureCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly encoding user input before outputting
        System.out.println("User Input: " + encodeForHTML(userInput));
    }

    public static String encodeForHTML(String input) {
        StringBuilder encodedString = new StringBuilder();

        for (char c : input.toCharArray()) {
            switch (c) {
                case '<':
                    encodedString.append("&lt;");
                    break;
                case '>':
                    encodedString.append("&gt;");
                    break;
                case '&':
                    encodedString.append("&amp;");
                    break;
                case '"':
                    encodedString.append("&quot;");
                    break;
                case '\'':
                    encodedString.append("&#x27;");
                    break;
                default:
                    encodedString.append(c);
            }
        }

        return encodedString.toString();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
